 65	static int
 66	class_index(size_t size)
 67	{
 68		int index = 0;
 69		size_t bound = MINBLOCKSIZE;
 70	
 71		while (index < LISTLIMIT - 1 && size > bound) {
 72			bound <<= 1;
 73			index++;
 74		}
 75		return (index);
 76	}
