 98	static void
 99	insert_free_block(void *bp)
100	{
101		int index = class_index(GET_SIZE(HDRP(bp)));
102		void *head = list_head(index);
103	
104		NEXT_FREEP(bp) = head;
105		PREV_FREEP(bp) = NULL;
106		if (head != NULL)
107			PREV_FREEP(head) = bp;
108		set_list_head(index, bp);
109	}
