111	static void
112	remove_free_block(void *bp)
113	{
114		int index = class_index(GET_SIZE(HDRP(bp)));
115		void *prev = PREV_FREEP(bp);
116		void *next = NEXT_FREEP(bp);
117	
118		if (prev != NULL)
119			NEXT_FREEP(prev) = next;
120		else
121			set_list_head(index, next);
122	
123		if (next != NULL)
124			PREV_FREEP(next) = prev;
125	}
