127	int
128	mm_init(void)
129	{
130		size_t initial_words = LISTLIMIT + 4;
131		char *base;
132	
133		if ((base = mem_sbrk(initial_words * WSIZE)) == (void *)-1)
134			return (-1);
135	
136		PUT(base, 0);
137		seglist_base = base + WSIZE;
138		for (int i = 0; i < LISTLIMIT; i++)
139			set_list_head(i, NULL);
140	
141		PUT(base + (LISTLIMIT + 1) * WSIZE, PACK(DSIZE, 1));
142		PUT(base + (LISTLIMIT + 2) * WSIZE, PACK(DSIZE, 1));
143		PUT(base + (LISTLIMIT + 3) * WSIZE, PACK(0, 1));
144	
145		heap_listp = base + (LISTLIMIT + 2) * WSIZE;
146		return (extend_heap(CHUNKSIZE / WSIZE) != NULL ? 0 : -1);
147	}
