149	static void *
150	extend_heap(size_t words)
151	{
152		size_t size;
153		void *bp;
154	
155		size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
156		if (size < MINBLOCKSIZE)
157			size = MINBLOCKSIZE;
158	
159		if ((bp = mem_sbrk((intptr_t)size)) == (void *)-1)
160			return (NULL);
161	
162		PUT(HDRP(bp), PACK(size, 0));
163		PUT(FTRP(bp), PACK(size, 0));
164		PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));
165		return (coalesce(bp));
166	}
167	
168	static void *
169	coalesce(void *bp)
170	{
171		bool prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
172		bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
173		size_t size = GET_SIZE(HDRP(bp));
174	
175		if (!prev_alloc) {
176			void *prev_bp = PREV_BLKP(bp);
177			remove_free_block(prev_bp);
178			size += GET_SIZE(HDRP(prev_bp));
179			PUT(HDRP(prev_bp), PACK(size, 0));
180			PUT(FTRP(bp), PACK(size, 0));
181			bp = prev_bp;
182		}
183	
184		if (!next_alloc) {
185			void *next_bp = NEXT_BLKP(bp);
186			remove_free_block(next_bp);
187			size += GET_SIZE(HDRP(next_bp));
188			PUT(HDRP(bp), PACK(size, 0));
189			PUT(FTRP(next_bp), PACK(size, 0));
190		}
191	
192		insert_free_block(bp);
193		return (bp);
194	}
