196	static void *
197	find_fit(size_t asize)
198	{
199		int index = class_index(asize);
200	
201		for (int i = index; i < LISTLIMIT; i++) {
202			void *bp = list_head(i);
203			void *best = NULL;
204			size_t best_size = ~(size_t)0;
205			int examined = 0;
206	
207			while (bp != NULL) {
208				size_t block_size = GET_SIZE(HDRP(bp));
209	
210				if (block_size >= asize) {
211					if (block_size == asize)
212						return (bp);
213					if (block_size < best_size) {
214						best = bp;
215						best_size = block_size;
216					}
217					if (examined >= 7)
218						break;
219				}
220				bp = NEXT_FREEP(bp);
221				examined++;
222			}
223			if (best != NULL)
224				return (best);
225		}
226		return (NULL);
227	}
