229	static void
230	place(void *bp, size_t asize)
231	{
232		size_t csize = GET_SIZE(HDRP(bp));
233	
234		remove_free_block(bp);
235		if (csize - asize >= MINBLOCKSIZE) {
236			void *next_bp;
237	
238			PUT(HDRP(bp), PACK(asize, 1));
239			PUT(FTRP(bp), PACK(asize, 1));
240			next_bp = NEXT_BLKP(bp);
241			PUT(HDRP(next_bp), PACK(csize - asize, 0));
242			PUT(FTRP(next_bp), PACK(csize - asize, 0));
243			insert_free_block(next_bp);
244		} else {
245			PUT(HDRP(bp), PACK(csize, 1));
246			PUT(FTRP(bp), PACK(csize, 1));
247		}
248	}
