302		}
303	
304		asize = adjust_block_size(size);
305		oldsize = GET_SIZE(HDRP(ptr));
306	
307		if (asize <= oldsize) {
308			size_t remainder = oldsize - asize;
309	
310			if (remainder >= MINBLOCKSIZE) {
311				void *split_bp;
312	
313				PUT(HDRP(ptr), PACK(asize, 1));
314				PUT(FTRP(ptr), PACK(asize, 1));
