316				PUT(HDRP(split_bp), PACK(remainder, 0));
317				PUT(FTRP(split_bp), PACK(remainder, 0));
318				NEXT_FREEP(split_bp) = NULL;
319				PREV_FREEP(split_bp) = NULL;
320				coalesce(split_bp);
321			}
322			return (ptr);
323		}
324	
325		if (!GET_ALLOC(HDRP(NEXT_BLKP(ptr)))) {
326			void *next_bp = NEXT_BLKP(ptr);
327			size_t combined = oldsize + GET_SIZE(HDRP(next_bp));
328	
329			if (combined >= asize) {
