396	static void
397	checkblock(void *bp)
398	{
399		if (!in_heap(bp))
400			printf("Error: block %p outside heap\n", bp);
401		if (!aligned(bp))
402			printf("Error: block %p is not aligned\n", bp);
403		if (GET(HDRP(bp)) != GET(FTRP(bp)))
