407	void
408	checkheap(bool verbose)
409	{
410		void *bp;
411		size_t free_blocks = 0;
412		size_t listed_blocks = 0;
413	
414		if (verbose)
415			printf("Heap (%p):\n", heap_listp);
416	
417		if (GET_SIZE(HDRP(heap_listp)) != DSIZE || !GET_ALLOC(HDRP(heap_listp)))
418			printf("Bad prologue header\n");
419	
420		for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
421			if (verbose)
422				printblock(bp);
423			checkblock(bp);
424			if (!GET_ALLOC(HDRP(bp))) {
425				free_blocks++;
426				if (!GET_ALLOC(HDRP(NEXT_BLKP(bp))) &&
427				    GET_SIZE(HDRP(NEXT_BLKP(bp))) > 0)
428					printf("Error: contiguous free blocks %p and %p not coalesced\n",
429					    bp, NEXT_BLKP(bp));
430			}

431		}
432	
433		if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
434			printf("Bad epilogue header\n");
435	
436		for (int i = 0; i < LISTLIMIT; i++) {
437			for (bp = list_head(i); bp != NULL; bp = NEXT_FREEP(bp)) {
438				listed_blocks++;
439				if (!in_heap(bp))
440					printf("Error: free list pointer %p outside heap\n", bp);
441				if (GET_ALLOC(HDRP(bp)))
442					printf("Error: allocated block %p in free list\n", bp);
443				if (PREV_FREEP(bp) != NULL && NEXT_FREEP(PREV_FREEP(bp)) != bp)
444					printf("Error: broken prev link at %p\n", bp);
445			}
446		}
447	
448		if (free_blocks != listed_blocks)
449			printf("Error: free block count mismatch heap=%zu list=%zu\n",
450			    free_blocks, listed_blocks);
451	}
